import 'package:flutter/material.dart';

class AppConfig {
  static const String appName = "Simple Todo";
  static const Color primaryColor = Color(0xFF635BFF);
  static const Color secondaryColor = Color(0xFF0A2540);
  static const Color backgroundColor = Color(0xFFF6F9FC);
  static const Color cardColor = Color(0xFFFFFFFF);
  static const double borderRadius = 16.0;
}

class TodoItem {
  final String id;
  String title;
  String category;
  bool isCompleted;

  TodoItem({
    required this.id,
    required this.title,
    required this.category,
    this.isCompleted = false,
  });
}

import 'package:flutter/material.dart';
import '../config/app_config.dart';
import '../models/todo_item.dart';

class TodoDashboardPage extends StatefulWidget {
  final List<TodoItem> tasks;
  final Function(TodoItem) onToggle;
  final Function(TodoItem) onDelete;
  final Function(String, String) onAdd;

  const TodoDashboardPage({
    Key? key,
    required this.tasks,
    required this.onToggle,
    required this.onDelete,
    required this.onAdd,
  }) : super(key: key);

  @override
  State<TodoDashboardPage> createState() => _TodoDashboardPageState();
}

class _TodoDashboardPageState extends State<TodoDashboardPage> {
  final TextEditingController _taskController = TextEditingController();
  String _selectedCategory = 'Personal';

  void _showAddTaskSheet(BuildContext context) {
    showModalBottomSheet(
      context: context,
      backgroundColor: Colors.transparent,
      isScrollControlled: true,
      builder: (context) {
        return StatefulBuilder(
          builder: (context, setModalState) {
            return Container(
              decoration: const BoxDecoration(
                color: AppConfig.cardColor,
                borderRadius: BorderRadius.only(
                  topLeft: Radius.circular(AppConfig.borderRadius),
                  topRight: Radius.circular(AppConfig.borderRadius),
                ),
              ),
              padding: EdgeInsets.only(
                top: 24,
                left: 24,
                right: 24,
                bottom: MediaQuery.of(context).viewInsets.bottom + 24,
              ),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  const Text(
                    'Create New Task',
                    style: TextStyle(
                      fontSize: 20,
                      fontWeight: FontWeight.bold,
                      color: AppConfig.secondaryColor,
                    ),
                  ),
                  const SizedBox(height: 16),
                  TextField(
                    controller: _taskController,
                    autofocus: true,
                    decoration: InputDecoration(
                      hintText: 'What needs to be done?',
                      hintStyle: TextStyle(color: Colors.grey.shade400),
                      filled: true,
                      fillColor: AppConfig.backgroundColor,
                      border: OutlineInputBorder(
                        borderRadius: BorderRadius.circular(12),
                        borderSide: BorderSide.none,
                      ),
                      contentPadding: const EdgeInsets.all(16),
                    ),
                  ),
                  const SizedBox(height: 16),
                  const Text(
                    'Category',
                    style: TextStyle(
                      fontSize: 14,
                      fontWeight: FontWeight.w600,
                      color: AppConfig.secondaryColor,
                    ),
                  ),
                  const SizedBox(height: 8),
                  Row(
                    children: ['Personal', 'Work', 'Urgent'].map((cat) {
                      final isSelected = _selectedCategory == cat;
                      return Padding(
                        padding: const EdgeInsets.only(right: 8.0),
                        child: ChoiceChip(
                          label: Text(cat),
                          selected: isSelected,
                          onSelected: (val) {
                            if (val) {
                              setModalState(() {
                                _selectedCategory = cat;
                              });
                              setState(() {
                                _selectedCategory = cat;
                              });
                            }
                          },
                          selectedColor: AppConfig.primaryColor.withOpacity(0.15),
                          backgroundColor: AppConfig.backgroundColor,
                          labelStyle: TextStyle(
                            color: isSelected ? AppConfig.primaryColor : AppConfig.secondaryColor,
                            fontWeight: isSelected ? FontWeight.bold : FontWeight.normal,
                          ),
                        ),
                      );
                    }).toList(),
                  ),
                  const SizedBox(height: 24),
                  SizedBox(
                    width: double.infinity,
                    height: 50,
                    child: ElevatedButton(
                      onPressed: () {
                        if (_taskController.text.trim().isNotEmpty) {
                          widget.onAdd(_taskController.text.trim(), _selectedCategory);
                          _taskController.clear();
                          Navigator.pop(context);
                        }
                      },
                      style: ElevatedButton.styleFrom(
                        backgroundColor: AppConfig.primaryColor,
                        foregroundColor: Colors.white,
                        shape: RoundedRectangleBorder(
                          borderRadius: BorderRadius.circular(12),
                        ),
                      ),
                      child: const Text('Add Task', style: TextStyle(fontWeight: FontWeight.bold)),
                    ),
                  ),
                ],
              ),
            );
          },
        );
      },
    );
  }

  @override
  Widget build(BuildContext context) {
    final total = widget.tasks.length;
    final completed = widget.tasks.where((t) => t.isCompleted).length;
    final double progress = total == 0 ? 0 : completed / total;

    return Scaffold(
      backgroundColor: AppConfig.backgroundColor,
      body: SafeArea(
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Padding(
              padding: const EdgeInsets.all(24.0),
              child: Row(
                mainAxisAlignment: MainAxisAlignment.spaceBetween,
                children: [
                  Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      const Text(
                        'My Space',
                        style: TextStyle(
                          fontSize: 28,
                          fontWeight: FontWeight.w800,
                          color: AppConfig.secondaryColor,
                        ),
                      ),
                      const SizedBox(height: 4),
                      Text(
                        '100% Offline & Secure',
                        style: TextStyle(
                          fontSize: 14,
                          fontWeight: FontWeight.w500,
                          color: AppConfig.primaryColor.withOpacity(0.8),
                        ),
                      ),
                    ],
                  ),
                  IconButton(
                    icon: const Icon(Icons.add_circle, color: AppConfig.primaryColor, size: 40),
                    onPressed: () => _showAddTaskSheet(context),
                  )
                ],
              ),
            ),
            // Beautiful Card-Based Metric Gauge
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: 24.0),
              child: Container(
                padding: const EdgeInsets.all(20),
                decoration: BoxDecoration(
                  color: AppConfig.cardColor,
                  borderRadius: BorderRadius.circular(AppConfig.borderRadius),
                  boxShadow: [
                    BoxShadow(
                      color: Colors.black.withOpacity(0.03),
                      blurRadius: 10,
                      offset: const Offset(0, 4),
                    )
                  ],
                ),
                child: Row(
                  children: [
                    SizedBox(
                      height: 64,
                      width: 64,
                      child: Stack(
                        fit: StackFit.expand,
                        children: [
                          CircularProgressIndicator(
                            value: progress,
                            strokeWidth: 8,
                            backgroundColor: AppConfig.backgroundColor,
                            color: AppConfig.primaryColor,
                          ),
                          Center(
                            child: Text(
                              '${(progress * 100).toInt()}%',
                              style: const TextStyle(
                                fontWeight: FontWeight.bold,
                                fontSize: 13,
                                color: AppConfig.secondaryColor,
                              ),
                            ),
                          )
                        ],
                      ),
                    ),
                    const SizedBox(width: 20),
                    Expanded(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          const Text(
                            'Daily Productivity',
                            style: TextStyle(
                              fontWeight: FontWeight.bold,
                              fontSize: 16,
                              color: AppConfig.secondaryColor,
                            ),
                          ),
                          const SizedBox(height: 4),
                          Text(
                            '$completed of $total tasks securely achieved today.',
                            style: TextStyle(
                              fontSize: 12,
                              color: Colors.grey.shade600,
                            ),
                          ),
                        ],
                      ),
                    )
                  ],
                ),
              ),
            ),
            const SizedBox(height: 24),
            const Padding(
              padding: EdgeInsets.symmetric(horizontal: 24.0),
              child: Text(
                'Tasks Checklist',
                style: TextStyle(
                  fontSize: 18,
                  fontWeight: FontWeight.bold,
                  color: AppConfig.secondaryColor,
                ),
              ),
            ),
            const SizedBox(height: 12),
            Expanded(
              child: widget.tasks.isEmpty
                  ? Center(
                      child: Column(
                        mainAxisAlignment: MainAxisAlignment.center,
                        children: [
                          Icon(Icons.assignment_turned_in_outlined, size: 64, color: Colors.grey.shade300),
                          const SizedBox(height: 16),
                          Text(
                            'All tasks clear!',
                            style: TextStyle(
                              fontSize: 16,
                              fontWeight: FontWeight.w600,
                              color: Colors.grey.shade500,
                            ),
                          ),
                          const SizedBox(height: 4),
                          Text(
                            'Add offline tasks safely to organize your day.',
                            style: TextStyle(
                              fontSize: 12,
                              color: Colors.grey.shade400,
                            ),
                          ),
                        ],
                      ),
                    )
                  : ListView.builder(
                      physics: const BouncingScrollPhysics(),
                      padding: const EdgeInsets.symmetric(horizontal: 24.0, vertical: 4.0),
                      itemCount: widget.tasks.length,
                      itemBuilder: (context, index) {
                        final item = widget.tasks[index];
                        return Dismissible(
                          key: Key(item.id),
                          direction: DismissDirection.endToStart,
                          background: Container(
                            alignment: Alignment.centerRight,
                            padding: const EdgeInsets.symmetric(horizontal: 20),
                            decoration: BoxDecoration(
                              color: Colors.red.shade50,
                              borderRadius: BorderRadius.circular(12),
                            ),
                            child: Icon(Icons.delete_outline, color: Colors.red.shade400),
                          ),
                          onDismissed: (dir) {
                            widget.onDelete(item);
                          },
                          child: Container(
                            margin: const EdgeInsets.only(bottom: 12),
                            decoration: BoxDecoration(
                              color: AppConfig.cardColor,
                              borderRadius: BorderRadius.circular(AppConfig.borderRadius - 4),
                              border: Border.all(color: Colors.grey.shade100, width: 1),
                            ),
                            child: ListTile(
                              leading: AnimatedSwitcher(
                                duration: const Duration(milliseconds: 300),
                                transitionBuilder: (child, anim) => ScaleTransition(scale: anim, child: child),
                                child: IconButton(
                                  key: ValueKey(item.isCompleted),
                                  icon: Icon(
                                    item.isCompleted ? Icons.check_circle_rounded : Icons.radio_button_off_rounded,
                                    color: item.isCompleted ? AppConfig.primaryColor : Colors.grey.shade400,
                                    size: 26,
                                  ),
                                  onPressed: () => widget.onToggle(item),
                                ),
                              ),
                              title: Text(
                                item.title,
                                style: TextStyle(
                                  fontSize: 15,
                                  fontWeight: FontWeight.w600,
                                  color: item.isCompleted ? Colors.grey : AppConfig.secondaryColor,
                                  decoration: item.isCompleted ? TextDecoration.lineThrough : null,
                                ),
                              ),
                              trailing: Container(
                                padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 4),
                                decoration: BoxDecoration(
                                  color: _getCategoryColor(item.category).withOpacity(0.12),
                                  borderRadius: BorderRadius.circular(20),
                                ),
                                child: Text(
                                  item.category,
                                  style: TextStyle(
                                    fontSize: 11,
                                    fontWeight: FontWeight.bold,
                                    color: _getCategoryColor(item.category),
                                  ),
                                ),
                              ),
                            ),
                          ),
                        ); 
                      },
                    ),
            ),
          ],
        ),
      ),
    );
  }

  Color _getCategoryColor(String category) {
    switch (category) {
      case 'Work':
        return Colors.blue.shade600;
      case 'Urgent':
        return Colors.red.shade400;
      default:
        return AppConfig.primaryColor;
    }
  }
}

import 'package:flutter/material.dart';
import '../config/app_config.dart';
import '../models/todo_item.dart';

class ProductivityStatsPage extends StatelessWidget {
  final List<TodoItem> tasks;

  const ProductivityStatsPage({Key? key, required this.tasks}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    final total = tasks.length;
    final completed = tasks.where((t) => t.isCompleted).length;
    final completionRate = total == 0 ? 0.0 : completed / total;
    final personalTasks = tasks.where((t) => t.category == 'Personal').length;
    final workTasks = tasks.where((t) => t.category == 'Work').length;
    final urgentTasks = tasks.where((t) => t.category == 'Urgent').length;

    return Scaffold(
      backgroundColor: AppConfig.backgroundColor,
      body: SafeArea(
        child: SingleChildScrollView(
          physics: const BouncingScrollPhysics(),
          child: Padding(
            padding: const EdgeInsets.all(24.0),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                const Text(
                  'Productivity Stats',
                  style: TextStyle(
                    fontSize: 28,
                    fontWeight: FontWeight.w800,
                    color: AppConfig.secondaryColor,
                  ),
                ),
                const SizedBox(height: 4),
                Text(
                  'Offline security compliance matrix & task analysis',
                  style: TextStyle(
                    fontSize: 14,
                    color: Colors.grey.shade600,
                  ),
                ),
                const SizedBox(height: 24),
                _buildProgressCard(completed, total, completionRate),
                const SizedBox(height: 24),
                const Text(
                  'Tasks Breakdown',
                  style: TextStyle(
                    fontSize: 18,
                    fontWeight: FontWeight.bold,
                    color: AppConfig.secondaryColor,
                  ),
                ),
                const SizedBox(height: 12),
                _buildBreakdownGrid(personalTasks, workTasks, urgentTasks),
                const SizedBox(height: 24),
                _buildSecurityShield(),
              ],
            ),
          ),
        ),
      ),
    );
  }

  Widget _buildProgressCard(int completed, int total, double rate) {
    return Container(
      padding: const EdgeInsets.all(24),
      decoration: BoxDecoration(
        color: AppConfig.cardColor,
        borderRadius: BorderRadius.circular(AppConfig.borderRadius),
        boxShadow: [
          BoxShadow(
            color: Colors.black.withOpacity(0.02),
            blurRadius: 10,
            offset: const Offset(0, 4),
          )
        ],
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          const Row(
            children: [
              Icon(Icons.analytics_outlined, color: AppConfig.primaryColor),
              SizedBox(width: 8),
              Text(
                'Performance Gauge',
                style: TextStyle(
                  fontSize: 16,
                  fontWeight: FontWeight.bold,
                  color: AppConfig.secondaryColor,
                ),
              ),
            ],
          ),
          const SizedBox(height: 20),
          LinearProgressIndicator(
            value: rate,
            backgroundColor: AppConfig.backgroundColor,
            color: AppConfig.primaryColor,
            minHeight: 12,
            borderRadius: BorderRadius.circular(6),
          ),
          const SizedBox(height: 16),
          Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            children: [
              Text(
                'Success Rate',
                style: TextStyle(color: Colors.grey.shade600, fontSize: 13),
              ),
              Text(
                '${(rate * 100).toInt()}%',
                style: const TextStyle(
                  fontSize: 16,
                  fontWeight: FontWeight.w800,
                  color: AppConfig.secondaryColor,
                ),
              ),
            ],
          )
        ],
      ),
    );
  }

  Widget _buildBreakdownGrid(int personal, int work, int urgent) {
    return GridView.count(
      crossAxisCount: 3,
      shrinkWrap: true,
      physics: const NeverScrollableScrollPhysics(),
      crossAxisSpacing: 12,
      mainAxisSpacing: 12,
      childAspectRatio: 0.9,
      children: [
        _buildStatBox('Personal', personal, AppConfig.primaryColor),
        _buildStatBox('Work', work, Colors.blue.shade600),
        _buildStatBox('Urgent', urgent, Colors.red.shade400),
      ],
    );
  }

  Widget _buildStatBox(String title, int count, Color color) {
    return Container(
      decoration: BoxDecoration(
        color: AppConfig.cardColor,
        borderRadius: BorderRadius.circular(AppConfig.borderRadius - 4),
        border: Border.all(color: Colors.grey.shade100, width: 1),
      ),
      child: Column(
        mainAxisAlignment: MainAxisAlignment.center,
        children: [
          Text(
            '$count',
            style: TextStyle(
              fontSize: 24,
              fontWeight: FontWeight.bold,
              color: color,
            ),
          ),
          const SizedBox(height: 4),
          Text(
            title,
            style: TextStyle(
              fontSize: 11,
              fontWeight: FontWeight.w600,
              color: Colors.grey.shade500,
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildSecurityShield() {
    return Container(
      padding: const EdgeInsets.all(20),
      decoration: BoxDecoration(
        color: AppConfig.primaryColor.withOpacity(0.06),
        borderRadius: BorderRadius.circular(AppConfig.borderRadius),
        border: Border.all(color: AppConfig.primaryColor.withOpacity(0.12)),
      ),
      child: const Row(
        children: [
          Icon(Icons.security, color: AppConfig.primaryColor, size: 32),
          SizedBox(width: 16),
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  'Stripe-Grade Security Shield',
                  style: TextStyle(
                    fontWeight: FontWeight.bold,
                    fontSize: 14,
                    color: AppConfig.secondaryColor,
                  ),
                ),
                SizedBox(height: 2),
                Text(
                  'Zero logs recorded externally. All data locked locally.',
                  style: TextStyle(fontSize: 12, color: AppConfig.secondaryColor),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }
}

import 'package:flutter/material.dart';
import 'config/app_config.dart';
import 'models/todo_item.dart';
import 'views/todo_dashboard_page.dart';
import 'views/productivity_stats_page.dart';

void main() {
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({Key? key}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: AppConfig.appName,
      debugShowCheckedModeBanner: false,
      theme: ThemeData(
        primaryColor: AppConfig.primaryColor,
        scaffoldBackgroundColor: AppConfig.backgroundColor,
        fontFamily: 'Outfit',
      ),
      home: const MainNavigationScreen(),
    );
  }
}

class MainNavigationScreen extends StatefulWidget {
  const MainNavigationScreen({Key? key}) : super(key: key);

  @override
  State<MainNavigationScreen> createState() => _MainNavigationScreenState();
}

class _MainNavigationScreenState extends State<MainNavigationScreen> {
  int _currentIndex = 0;

  // Base high-fidelity mock data mimicking localized database storage
  final List<TodoItem> _tasks = [
    TodoItem(id: '1', title: 'Prepare design system proposal', category: 'Work', isCompleted: true),
    TodoItem(id: '2', title: 'Review local keychain integration', category: 'Urgent', isCompleted: false),
    TodoItem(id: '3', title: 'Plan Sunday mindful layout session', category: 'Personal', isCompleted: false),
  ];

  void _toggleTask(TodoItem item) {
    setState(() {
      item.isCompleted = !item.isCompleted;
    });
  }

  void _deleteTask(TodoItem item) {
    setState(() {
      _tasks.removeWhere((t) => t.id == item.id);
    });
  }

  void _addNewTask(String title, String category) {
    setState(() {
      _tasks.insert(
        0,
        TodoItem(
          id: DateTime.now().toIso8601String(),
          title: title,
          category: category,
        ),
      );
    });
  }

  @override
  Widget build(BuildContext context) {
    final List<Widget> _pages = [
      TodoDashboardPage(
        tasks: _tasks,
        onToggle: _toggleTask,
        onDelete: _deleteTask,
        onAdd: _addNewTask,
      ),
      ProductivityStatsPage(tasks: _tasks),
    ];

    return Scaffold(
      body: _pages[_currentIndex],
      bottomNavigationBar: Container(
        decoration: BoxDecoration(
          border: Border(
            top: BorderSide(color: Colors.grey.shade100, width: 1),
          ),
        ),
        child: BottomNavigationBar(
          currentIndex: _currentIndex,
          onTap: (index) {
            setState(() {
              _currentIndex = index;
            });
          },
          backgroundColor: AppConfig.cardColor,
          selectedItemColor: AppConfig.primaryColor,
          unselectedItemColor: Colors.grey.shade400,
          selectedFontSize: 12,
          unselectedFontSize: 12,
          type: BottomNavigationBarType.fixed,
          elevation: 0,
          items: const [
            BottomNavigationBarItem(
              icon: Icon(Icons.check_box_outlined),
              activeIcon: Icon(Icons.check_box_rounded),
              label: 'Checklist',
            ),
            BottomNavigationBarItem(
              icon: Icon(Icons.bar_chart_outlined),
              activeIcon: Icon(Icons.bar_chart_rounded),
              label: 'Metrics',
            ),
          ],
        ),
      ),
    );
  }
}
